import{_ as c,r as i,o as d,c as u,a as e,b as t,t as s,d as o,w as l,e as h}from"./app-d223f2a5.js";const p={},w={id:"frontmatter-title-관련",tabindex:"-1"},g=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),f={class:"table-of-contents"},m=h('<hr><h2 id="project-9-part-4" tabindex="-1"><a class="header-anchor" href="#project-9-part-4" aria-hidden="true">#</a> Project 9, part 4</h2><p>That’s another project finished, and at this point you’ve had a taste of almost all of SwiftUI’s drawing APIs. Chances are you want to get back to building apps, but please take a moment to pause and review what you’ve learned – you might not <em>use</em> all of it for some time, but it’s important you at least <em>remember</em> what was covered so you can refer back to it later.</p><p>So, today you have another review to test what you remember, and also some challenges to get you coding yourself. As always these challenges don’t come with solutions by me, but that’s the point – as American NFL player Troy Polamalu once said, “I’ve always had the mind-set that no one can challenge me better than myself.”</p><p>You have free rein to solve them however you want and in whatever time you want, and you might sail through problem-free. On the other hand, perhaps in completing them you’ll spot a few places where your knowledge was a bit shaky – the only way you’ll know is if you try.</p><p><strong>Today you should work through the wrap up chapter for project 9, complete its review, then work through all three of its challenges.</strong></p><h3 id="drawing-wrap-up" tabindex="-1"><a class="header-anchor" href="#drawing-wrap-up" aria-hidden="true">#</a> Drawing: Wrap up</h3><p>::: detatils Drawing: Wrap up</p>',8),y={href:"https://www.hackingwithswift.com/books/ios-swiftui/drawing-wrap-up",target:"_blank",rel:"noopener noreferrer"},_=e("p",null,"We covered a huge amount of ground in this project, and you’ve learned about paths, shapes, strokes, transforms, drawing groups, animating values, and more. Not everyone will want to use all those features, and that’s OK – hopefully you have a clear idea of which parts interested you the most, and have some good coding experience with them.",-1),b=e("p",null,[t("If you combine your new-found drawing abilities with all the animation functionality we covered back in project 6, I hope you’re starting to realize just how much power and flexibility SwiftUI gives us. Yes, you can of course create whole apps using "),e("code",null,"List"),t(", "),e("code",null,"NavigationView"),t(", and similar, but you can also build completely custom user interfaces that look fantastic and are just as fast.")],-1),k=e("h4",{id:"review-what-you-learned",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#review-what-you-learned","aria-hidden":"true"},"#"),t(" Review what you learned")],-1),v=e("p",null,"Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.",-1),j={href:"https://www.hackingwithswift.com/review/ios-swiftui/drawing",target:"_blank",rel:"noopener noreferrer"},x=h('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try extending this app to make sure you fully understand what’s going on.</p><ol><li>Create an <code>Arrow</code> shape – having it point straight up is fine. This could be a rectangle/triangle-style arrow, or perhaps three lines, or maybe something else depending on what kind of arrow you want to draw.</li><li>Make the line thickness of your <code>Arrow</code> shape animatable.</li><li>Create a <code>ColorCyclingRectangle</code> shape that is the rectangular cousin of <code>ColorCyclingCircle</code>, allowing us to control the position of the gradient using one or more properties.</li></ol><p><strong>Tip</strong>: Gradient positions like <code>.top</code> and <code>.bottom</code> are actually instances of <code>UnitPoint</code>, and you can create your own <code>UnitPoint</code> instances with X/Y values ranging from 0 to 1.</p><p>:::</p>',5),C={class:"hint-container info"},I=e("p",{class:"hint-container-title"},"Drawing: Wrap up - Additional",-1),A={href:"https://www.hackingwithswift.com/review/ios-swiftui/drawing",target:"_blank",rel:"noopener noreferrer"};function N(n,P){const r=i("router-link"),a=i("ExternalLinkIcon");return d(),u("div",null,[e("h1",w,[g,t(" "+s(n.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,s(n.$frontmatter.description),1)]),e("nav",f,[e("ul",null,[e("li",null,[o(r,{to:"#project-9-part-4"},{default:l(()=>[t("Project 9, part 4")]),_:1}),e("ul",null,[e("li",null,[o(r,{to:"#drawing-wrap-up"},{default:l(()=>[t("Drawing: Wrap up")]),_:1})])])])])]),m,e("p",null,[e("a",y,[t("📎link"),o(a)])]),_,b,k,v,e("p",null,[e("a",j,[t("Click here to review what you learned in this project."),o(a)])]),x,e("div",C,[I,e("p",null,[e("a",A,[t("Review for Project 9: Drawing"),o(a)])])])])}const T=c(p,[["render",N],["__file","46.html.vue"]]);export{T as default};
